import os
from sklearn.externals import joblib
import boto3

def load_latest_model(model_path_prefix):
    s3 = boto3.client('s3')
    bucket_name, key_prefix = model_path_prefix.split('/', 1)
    response = s3.list_objects_v2(Bucket=bucket_name, Prefix=key_prefix)

    if 'Contents' not in response:
        raise ValueError("No models found in the specified path.")

    latest_model_key = max(
        (content['Key'] for content in response['Contents']),
        key=lambda x: x.rsplit('-', 1)[0] + x.rsplit('.', 1)[1]
    )

    local_model_path = '/tmp/latest_model.pkl'
    s3.download_file(bucket_name, latest_model_key, local_model_path)
    
    return joblib.load(local_model_path)

if __name__ == "__main__":
    model_path_prefix = os.getenv('MODEL_PATH')
    if not model_path_prefix:
        raise ValueError("Environment variable MODEL_PATH is not set.")

    model = load_latest_model(model_path_prefix)
    print("Model loaded successfully.")